"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[3423],{56082:e=>{e.exports=JSON.parse('{"tag":{"label":"worldgen","permalink":"/dst-api-webdocs/docs/tags/worldgen","allTagsPath":"/dst-api-webdocs/docs/tags","count":27,"items":[{"id":"game-scripts/map/static_layouts/adventure_portal_layout","title":"Adventure Portal Layout","description":"A static map layout definition used to position entities (e.g., adventure portals, flora, lighting) in the Adventure mode portal room.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/adventure_portal_layout"},{"id":"game-scripts/map/archive_worldgen","title":"Archive Worldgen","description":"This module initializes and adjusts entities for the Ancient Archive worldgen pass, specifically populating lockbox dispensers with predefined products in a cyclic order.","permalink":"/dst-api-webdocs/docs/game-scripts/map/archive_worldgen"},{"id":"game-scripts/map/static_layouts/archivedoor","title":"Archivedoor","description":"A static layout configuration for the archived door area in DST caves, defining tilemap data, object placement, and map metadata for world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/archivedoor"},{"id":"game-scripts/map/rooms/forest/bee","title":"Bee","description":"Defines forest room templates for bee-related biomes, including standard bee clearings and queen bee nests, specifying tile type, colour, and prefab spawn rules.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/bee"},{"id":"game-scripts/map/bunches","title":"Bunches","description":"Defines static spawning rules for grouped environmental props (bunches) such as seastacks, saltstacks, and rubbles across specific tile types.","permalink":"/dst-api-webdocs/docs/game-scripts/map/bunches"},{"id":"game-scripts/map/levels/caves","title":"Caves","description":"Registers and configures cave-level world generation presets and settings for the Caves dimension in Don\'t Starve Together, including default, enhanced (Cave Plus), and Terraria-style variants.","permalink":"/dst-api-webdocs/docs/game-scripts/map/levels/caves"},{"id":"game-scripts/map/rooms/cave/generic","title":"Generic","description":"Defines static cave room templates including impassable pit rooms and cave exit rooms with distributed flora and light assets.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/generic"},{"id":"game-scripts/map/levels/lavaarena","title":"Lavaarena","description":"Registers the Lavaarena level configuration with the game\'s world generation and customization systems, defining its display strings, metadata, and feature restrictions.","permalink":"/dst-api-webdocs/docs/game-scripts/map/levels/lavaarena"},{"id":"game-scripts/map/level","title":"Level","description":"Manages level configuration including task selection, set piece assignment, and world generation overrides for map generation in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/map/level"},{"id":"game-scripts/map/levels","title":"Levels","description":"Central registry and manager for level configurations, settings presets, and world generation definitions in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/map/levels"},{"id":"game-scripts/map/rooms/forest/mandrake","title":"Mandrake","description":"Registers a custom forest room (MandrakeHome) that occasionally spawns a mandrake_planted prefab among natural flora and structures.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/mandrake"},{"id":"game-scripts/map/maptags","title":"Maptags","description":"Provides a central registry of map-specific tags and spawner configurations used during level generation in DST\'s worldgen system.","permalink":"/dst-api-webdocs/docs/game-scripts/map/maptags"},{"id":"game-scripts/map/maze_layouts","title":"Maze Layouts","description":"Factory module that pre-generates and caches static maze room layouts for the Archive and Ruins biomes with configurable area content and rotation variants.","permalink":"/dst-api-webdocs/docs/game-scripts/map/maze_layouts"},{"id":"game-scripts/map/monkeyisland_worldgen","title":"Monkeyisland Worldgen","description":"Generates dock systems and associated assets for monkey islands during world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/monkeyisland_worldgen"},{"id":"game-scripts/map/network","title":"Network","description":"Manages world map graph structure including nodes, edges, and child subgraphs for procedural level generation and rendering in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/map/network"},{"id":"game-scripts/map/ocean_retrofit_island","title":"Ocean Retrofit Island","description":"A map-generation utility module that inserts ocean-based setpieces (moon islands, hermit islands, crab kings, waterlog biomes, monkey islands) into an existing world by validating terrain constraints and adding topology nodes.","permalink":"/dst-api-webdocs/docs/game-scripts/map/ocean_retrofit_island"},{"id":"game-scripts/map/rooms/cave/rabbits","title":"Rabbits","description":"Defines cave-level room templates for rabbit warrens and related environments, including RabbitArea, RabbitTown, RabbitCity, RabbitSinkhole, and SpiderIncursion.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/rabbits"},{"id":"game-scripts/map/resource_substitution","title":"Resource Substitution","description":"Provides a mapping and random selection mechanism for substituting game resources (e.g., rocks, trees, grass) with alternate variants based on predefined rules.","permalink":"/dst-api-webdocs/docs/game-scripts/map/resource_substitution"},{"id":"game-scripts/map/retrofit_savedata","title":"Retrofit Savedata","description":"A utility module that applies worldgen retrofits to saved game data, updating legacy maps with new content and mechanics introduced in the Return of Them, Waterlogged, and other DLC updates.","permalink":"/dst-api-webdocs/docs/game-scripts/map/retrofit_savedata"},{"id":"game-scripts/map/rooms/cave/rocky","title":"Rocky","description":"Defines several cave room templates containing variable distributions of rocks, pillars, slurtle holes, bats, and other environmental props for world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/rocky"},{"id":"game-scripts/map/rooms/cave/sinkhole","title":"Sinkhole","description":"Defines procedural cave room templates for sinkhole biomes in the world generation system, specifying decoration rules, static layouts, and visual properties.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/sinkhole"},{"id":"game-scripts/map/rooms/forest/starts","title":"Starts","description":"Registers predefined room templates for the forest world type, including custom starting areas like Burnt Forest and Safe Swamp, defining tile type, visual appearance, and content distribution rules.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/starts"},{"id":"game-scripts/map/rooms/cave/swamp","title":"Swamp","description":"Defines cave swamp map room templates with varying layouts, densities, and prefab distributions for procedural world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/swamp"},{"id":"game-scripts/map/tasksets","title":"Tasksets","description":"Manages registration, retrieval, and listing of task group definitions for world generation across different game locations (forest, caves, lava arena, quagmire).","permalink":"/dst-api-webdocs/docs/game-scripts/map/tasksets"},{"id":"game-scripts/map/rooms/test","title":"Test","description":"Defines debug and test room templates for world generation, primarily used to validate static layouts and prefab distributions during development.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/test"},{"id":"game-scripts/map/rooms/forest/walrus","title":"Walrus","description":"Registers three room variants for walrus camps in forest worlds, each with distinct tile types, spawn configurations, and weighted prefab distributions.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/walrus"},{"id":"game-scripts/map/waterlog_worldgen","title":"Waterlog Worldgen","description":"Generates waterlog terrain features and marker entities in ocean regions during world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/waterlog_worldgen"}],"unlisted":false}}')}}]);